35	// NewReframePostLadderExhaustionHook creates a PostLadderExhaustionHook that
36	// dispatches runReframer for SpecGap and PersistentExecutionFailed failure
37	// classes. TooLarge is not handled here; it belongs to the Decompose path.
38	func NewReframePostLadderExhaustionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) PostLadderExhaustionHook {
39		return func(ctx context.Context, beadID string, failureClass RecoveryFailureClass) (*PostLadderExhaustionResult, error) {
40			switch failureClass {
41			case SpecGap, PersistentExecutionFailed:
42			default:
43				return &PostLadderExhaustionResult{Attempted: false}, nil
44			}
45			result := runReframer(ctx, store, runner, rcfg, projectRoot, beadID)
46			if result.Failed {
47				return &PostLadderExhaustionResult{
48					Attempted: true,
49					Succeeded: false,
50					Path:      Reframe,
51				}, nil
52			}
53			return &PostLadderExhaustionResult{
54				Attempted: true,
55				Succeeded: true,
56				Path:      Reframe,
57				CostUSD:   result.CostUSD,
58			}, nil
59		}
60	}
