62	// runReframer dispatches a smart+ tier agent to rewrite the bead's description
63	// and acceptance criteria after the escalation ladder has been exhausted.
64	// On success, the bead description/AC are updated, the
65	// consecutive_ladder_exhaustions counter is cleared, and a "reframe-applied"
66	// event is emitted. On failure a ReframeResult with Failed=true is returned.
67	func runReframer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) ReframeResult {
68		tctx, cancel := context.WithTimeout(ctx, reframerDefaultTimeout)
69		defer cancel()
70	
71		b, err := store.Get(beadID)
72		if err != nil {
73			return ReframeResult{Failed: true, Reason: "store_error"}
74		}
75	
76		prompt, err := buildReframerPrompt(store, b)
77		if err != nil {
78			return ReframeResult{Failed: true, Reason: "prompt_error"}
79		}
80	
81		runtime := AgentRunRuntime{
82			Prompt:           prompt,
83			WorkDir:          projectRoot,
84			PromptSource:     reframerPromptSource,
85			ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
86			ClearRoutingPins: true,
87			ClearProfile:     true,
88			ClearMinPower:    true,
89			ClearMaxPower:    true,
90		}
91	
92		result, err := dispatchViaResolvedConfig(tctx, projectRoot, nil, runner, rcfg, runtime)
93		if err != nil {
94			if tctx.Err() != nil {
95				return ReframeResult{Failed: true, Reason: "timeout"}
96			}
97			return ReframeResult{Failed: true, Reason: "dispatch_error"}
98		}
99	
100		output := strings.TrimSpace(result.CondensedOutput)
101		if output == "" {
102			output = strings.TrimSpace(result.Output)
103		}
104		if output == "" {
105			return ReframeResult{Failed: true, Reason: "empty_output"}
106		}
107	
108		candidate, ok := extractJSONCandidate(output)
109		if !ok {
110			return ReframeResult{Failed: true, Reason: "invalid_output"}
111		}
112	
113		var parsed reframerOutput
114		if err := json.Unmarshal([]byte(candidate), &parsed); err != nil {
115			return ReframeResult{Failed: true, Reason: "invalid_output"}
116		}
117		if parsed.Description == nil && parsed.Acceptance == nil {
118			return ReframeResult{Failed: true, Reason: "invalid_output"}
119		}
120	
121		current, err := store.Get(beadID)
122		if err != nil {
123			return ReframeResult{Failed: true, Reason: "store_error"}
124		}
125	
126		descChanged := parsed.Description != nil &&
127			strings.TrimSpace(*parsed.Description) != strings.TrimSpace(current.Description)
128		accChanged := parsed.Acceptance != nil &&
129			strings.TrimSpace(*parsed.Acceptance) != strings.TrimSpace(current.Acceptance)
130	
131		if !descChanged && !accChanged {
132			return ReframeResult{Failed: true, Reason: "noop_edits"}
133		}
134	
135		var changedFields []string
136		var rewrite PreClaimIntakeRewrite
137		if descChanged {
138			changedFields = append(changedFields, "description")
139			rewrite.Description = strings.TrimSpace(*parsed.Description)
140		}
141		if accChanged {
142			changedFields = append(changedFields, "acceptance")
143			rewrite.Acceptance = strings.TrimSpace(*parsed.Acceptance)
144		}
145		rewrite.ChangedFields = changedFields
146	
147		intake := PreClaimIntakeResult{
148			Outcome: PreClaimIntakeActionableButRewritten,
149			Detail:  "reframer rewrote bead after exhaustion",
150			Rewrite: rewrite,
151		}
152	
153		if err := applyPreClaimIntakeRewrite(store, beadID, "ddx agent execute-loop", intake, time.Now()); err != nil {
154			return ReframeResult{Failed: true, Reason: "apply_error"}
155		}
156	
157		_ = store.Update(beadID, func(b *bead.Bead) {
158			ensureBeadExtra(b)
159			delete(b.Extra, consecutiveLadderExhaustionsKey)
160		})
161	
162		body, _ := json.Marshal(reframerEventBody{
163			CostUSD:            result.CostUSD,
164			DescriptionChanged: descChanged,
165			AcceptanceChanged:  accChanged,
166		})
167		_ = store.AppendEvent(beadID, bead.BeadEvent{
168			Kind:      "reframe-applied",
169			Summary:   strings.Join(changedFields, ","),
170			Body:      string(body),
171			Actor:     "ddx agent execute-loop",
172			Source:    "ddx agent execute-loop",
173			CreatedAt: time.Now().UTC(),
174		})
175	
176		return ReframeResult{
177			Failed:  false,
178			CostUSD: result.CostUSD,
179		}
180	}
