package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
)

const decomposerPromptSource = "bead-lifecycle-decompose"
const decomposerDefaultTimeout = 5 * time.Minute

// DecomposeResult is the outcome of a runDecomposer invocation.
type DecomposeResult struct {
	Failed   bool
	Reason   string
	CostUSD  float64
	ChildIDs []string
}

type decomposerChild struct {
	Title       string   `json:"title"`
	Description string   `json:"description"`
	Acceptance  string   `json:"acceptance"`
	Labels      []string `json:"labels"`
}

type decomposerEventBody struct {
	CostUSD  float64  `json:"cost_usd,omitempty"`
	ChildIDs []string `json:"child_ids"`
}

// NewDecomposePostLadderExhaustionHook creates a PostLadderExhaustionHook that
// dispatches runDecomposer for the TooLarge failure class.
func NewDecomposePostLadderExhaustionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) PostLadderExhaustionHook {
	return func(ctx context.Context, beadID string, failureClass RecoveryFailureClass) (*PostLadderExhaustionResult, error) {
		if failureClass != TooLarge {
			return &PostLadderExhaustionResult{Attempted: false}, nil
		}
		result := runDecomposer(ctx, store, runner, rcfg, projectRoot, beadID)
		if result.Failed {
			return &PostLadderExhaustionResult{
				Attempted: true,
				Succeeded: false,
				Path:      Decompose,
			}, nil
		}
		return &PostLadderExhaustionResult{
			Attempted: true,
			Succeeded: true,
			Path:      Decompose,
			CostUSD:   result.CostUSD,
		}, nil
	}
}

// runDecomposer dispatches a smart+ tier agent to decompose a too-large bead
// into child beads after the escalation ladder has been exhausted.
// On success, child beads are created with Parent=beadID, the parent is marked
// execution-eligible=false, and a decompose-applied event is emitted.
// On failure a DecomposeResult with Failed=true is returned.
func runDecomposer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) DecomposeResult {
	tctx, cancel := context.WithTimeout(ctx, decomposerDefaultTimeout)
	defer cancel()

	b, err := store.Get(beadID)
	if err != nil {
		return DecomposeResult{Failed: true, Reason: "store_error"}
	}

	prompt, err := buildDecomposerPrompt(store, b)
	if err != nil {
		return DecomposeResult{Failed: true, Reason: "prompt_error"}
	}

	runtime := AgentRunRuntime{
		Prompt:           prompt,
		WorkDir:          projectRoot,
		PromptSource:     decomposerPromptSource,
		ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
		ClearRoutingPins: true,
		ClearProfile:     true,
		ClearMinPower:    true,
		ClearMaxPower:    true,
	}

	result, err := dispatchViaResolvedConfig(tctx, projectRoot, nil, runner, rcfg, runtime)
	if err != nil {
		if tctx.Err() != nil {
			return DecomposeResult{Failed: true, Reason: "timeout"}
		}
		return DecomposeResult{Failed: true, Reason: "dispatch_error"}
	}

	output := strings.TrimSpace(result.CondensedOutput)
	if output == "" {
		output = strings.TrimSpace(result.Output)
	}
	if output == "" {
		return DecomposeResult{Failed: true, Reason: "empty_output"}
	}

	candidate, ok := extractJSONArrayCandidate(output)
	if !ok {
		return DecomposeResult{Failed: true, Reason: "invalid_output"}
	}

	var children []decomposerChild
	if err := json.Unmarshal([]byte(candidate), &children); err != nil {
		return DecomposeResult{Failed: true, Reason: "invalid_output"}
	}

	if len(children) < 1 || len(children) > 5 {
		return DecomposeResult{Failed: true, Reason: "invalid_count"}
	}

	for _, child := range children {
		if strings.TrimSpace(child.Title) == "" ||
			strings.TrimSpace(child.Description) == "" ||
			strings.TrimSpace(child.Acceptance) == "" {
			return DecomposeResult{Failed: true, Reason: "malformed_child"}
		}
	}

	childIDs := make([]string, 0, len(children))
	for _, child := range children {
		nb := &bead.Bead{
			Title:       strings.TrimSpace(child.Title),
			Description: strings.TrimSpace(child.Description),
			Acceptance:  strings.TrimSpace(child.Acceptance),
			Labels:      append([]string(nil), child.Labels...),
			Parent:      beadID,
		}
		if err := store.Create(nb); err != nil {
			return DecomposeResult{Failed: true, Reason: "store_error"}
		}
		childIDs = append(childIDs, nb.ID)
	}

	_ = store.Update(beadID, func(b *bead.Bead) {
		ensureBeadExtra(b)
		b.Extra[bead.ExtraExecutionElig] = false
	})

	body, _ := json.Marshal(decomposerEventBody{
		CostUSD:  result.CostUSD,
		ChildIDs: childIDs,
	})
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "decompose-applied",
		Summary:   fmt.Sprintf("decomposed into %s", strings.Join(childIDs, ", ")),
		Body:      string(body),
		Actor:     "ddx agent execute-loop",
		Source:    "ddx agent execute-loop",
		CreatedAt: time.Now().UTC(),
	})

	return DecomposeResult{
		Failed:   false,
		CostUSD:  result.CostUSD,
		ChildIDs: childIDs,
	}
}

func buildDecomposerPrompt(store ExecuteBeadLoopStore, b *bead.Bead) (string, error) {
	type failureEntry struct {
		Summary string `json:"summary"`
		Body    string `json:"body,omitempty"`
	}
	type envelope struct {
		Title          string         `json:"title"`
		Description    string         `json:"description"`
		Acceptance     string         `json:"acceptance"`
		FailureHistory []failureEntry `json:"failure_history"`
	}

	env := envelope{
		Title:       strings.TrimSpace(b.Title),
		Description: strings.TrimSpace(b.Description),
		Acceptance:  strings.TrimSpace(b.Acceptance),
	}

	if events, err := store.Events(b.ID); err == nil {
		for i := len(events) - 1; i >= 0 && len(env.FailureHistory) < 5; i-- {
			ev := events[i]
			switch ev.Kind {
			case "bead.result", "execute-bead", "per-bead-budget-exhausted":
			default:
				continue
			}
			env.FailureHistory = append(env.FailureHistory, failureEntry{
				Summary: strings.TrimSpace(ev.Summary),
				Body:    strings.TrimSpace(ev.Body),
			})
		}
	}

	body, err := json.MarshalIndent(env, "", "  ")
	if err != nil {
		return "", fmt.Errorf("decomposer: encode prompt: %w", err)
	}

	var sb strings.Builder
	sb.WriteString("MODE: decompose\n")
	sb.WriteString("You are decomposing a bead that is too large into 2-5 independently executable child beads.\n")
	sb.WriteString("Return exactly one JSON array where each element has: title (string), description (string), acceptance (string), labels ([]string).\n")
	sb.WriteString("Every title, description, and acceptance must be non-empty.\n")
	sb.WriteString("Do not include prose or markdown fences; return only the JSON array.\n\n")
	sb.WriteString("```json\n")
	sb.Write(body)
	sb.WriteString("\n```\n")
	return sb.String(), nil
}

// extractJSONArrayCandidate extracts a JSON array candidate from agent output.
// It tries, in order:
//  1. The body of the last ```json … ``` fenced block when it starts with '['.
//  2. The body of the last ``` … ``` fenced block when it starts with '['.
//  3. The substring from the first '[' that balances brackets.
func extractJSONArrayCandidate(s string) (string, bool) {
	if c, ok := lastFencedBlock(s, "json"); ok {
		if trimmed := strings.TrimSpace(c); strings.HasPrefix(trimmed, "[") {
			return trimmed, true
		}
	}
	if c, ok := lastFencedBlock(s, ""); ok {
		if trimmed := strings.TrimSpace(c); strings.HasPrefix(trimmed, "[") {
			return trimmed, true
		}
	}
	return firstBalancedArray(s)
}

// firstBalancedArray scans for the first '[' in s and returns the substring
// that closes its outermost JSON array, respecting strings and escapes.
// Returns ok=false on no opening bracket or on an unterminated array.
func firstBalancedArray(s string) (string, bool) {
	start := strings.Index(s, "[")
	if start < 0 {
		return "", false
	}
	depth := 0
	inString := false
	escape := false
	for i := start; i < len(s); i++ {
		c := s[i]
		if escape {
			escape = false
			continue
		}
		if inString {
			switch c {
			case '\\':
				escape = true
			case '"':
				inString = false
			}
			continue
		}
		switch c {
		case '"':
			inString = true
		case '[':
			depth++
		case ']':
			depth--
			if depth == 0 {
				return s[start : i+1], true
			}
		}
	}
	return "", false
}

package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent/executeloop"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestPostLadderExhaustion_TriggersDecompose_ReviewTooLarge verifies that a
// TooLarge failure class routes to runDecomposer, and on valid children creates
// child beads and sets parent execution-eligible=false.
func TestPostLadderExhaustion_TriggersDecompose_ReviewTooLarge(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	b := &bead.Bead{
		ID:          "ddx-decompose-toolarge",
		Title:       "decompose too-large test",
		Description: "PROBLEM\nThis bead is too large.\n\nROOT CAUSE\ncli/internal/agent/foo.go:42 has too many concerns.\n",
		Acceptance:  "1. TestPostLadderExhaustion_TriggersDecompose_ReviewTooLarge passes\n2. cd cli && go test ./internal/agent/... green\n",
	}
	require.NoError(t, store.Create(b))

	// Pre-seed counter to 1 so the next budget exhaustion hits the threshold.
	require.NoError(t, incrementConsecutiveLadderExhaustions(store, b.ID))

	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	var decomposeDispatched bool
	decomposeRunner := reframeRunnerFunc(func(opts RunArgs) (*Result, error) {
		decomposeDispatched = true
		cancel() // stop the loop after the decomposer fires
		children := []map[string]interface{}{
			{
				"title":       "Child bead one",
				"description": "PROBLEM\nFirst child concern.",
				"acceptance":  "1. Child one AC passes",
				"labels":      []string{"phase:6"},
			},
			{
				"title":       "Child bead two",
				"description": "PROBLEM\nSecond child concern.",
				"acceptance":  "1. Child two AC passes",
				"labels":      []string{"phase:6"},
			},
		}
		out, _ := json.Marshal(children)
		return &Result{ExitCode: 0, Output: string(out), CostUSD: 0.0077}, nil
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	hook := NewDecomposePostLadderExhaustionHook(store, decomposeRunner, rcfg, t.TempDir())

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusExecutionFailed + "_" + ReviewTerminalClassTooLarge,
				Detail:    escalation.PerBeadBudgetExhaustedReason + ": $1.00 billed >= $0.50 per-bead budget",
				SessionID: "sess-decompose-toolarge",
			}, nil
		}),
	}

	_, _ = worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:                     executeloop.ModeDrain,
		PostLadderExhaustionHook: hook,
		ProjectRoot:              t.TempDir(),
		SessionID:                "sess-decompose-toolarge",
		WorkerID:                 "worker-decompose-toolarge",
	})

	assert.True(t, decomposeDispatched, "decomposer must be dispatched for TooLarge class")

	got, err := store.Get(b.ID)
	require.NoError(t, err)
	assert.Equal(t, false, got.Extra[bead.ExtraExecutionElig], "parent must be marked execution-eligible=false")

	all, err := store.ReadAll()
	require.NoError(t, err)
	var childBeads []bead.Bead
	for _, child := range all {
		if child.Parent == b.ID {
			childBeads = append(childBeads, child)
		}
	}
	assert.Len(t, childBeads, 2, "2 child beads must be created")

	events, err := store.Events(b.ID)
	require.NoError(t, err)
	var decompApplied bool
	for _, ev := range events {
		if ev.Kind == "decompose-applied" {
			decompApplied = true
			assert.Contains(t, ev.Body, "child_ids", "decompose-applied event body must contain child_ids field")
			assert.Contains(t, ev.Body, "cost_usd", "decompose-applied event body must contain cost_usd field")
		}
	}
	assert.True(t, decompApplied, "decompose-applied event must be emitted")
}

// TestDecomposerInvalidChildren_CountsAsFailure verifies that a stub agent
// returning more than 5 children yields DecomposeResult{Failed:true, Reason:"invalid_count"}.
func TestDecomposerInvalidChildren_CountsAsFailure(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	b := &bead.Bead{
		ID:          "ddx-decompose-overflow",
		Title:       "decompose overflow test",
		Description: "PROBLEM\nOverflow test.",
		Acceptance:  "1. TestDecomposerInvalidChildren_CountsAsFailure\n",
	}
	require.NoError(t, store.Create(b))

	// Return 6 children — more than the 5-child cap.
	overflowRunner := reframeRunnerFunc(func(opts RunArgs) (*Result, error) {
		children := make([]map[string]interface{}, 6)
		for i := range children {
			children[i] = map[string]interface{}{
				"title":       fmt.Sprintf("Child %d", i+1),
				"description": "desc",
				"acceptance":  "1. AC",
				"labels":      []string{},
			}
		}
		out, _ := json.Marshal(children)
		return &Result{ExitCode: 0, Output: string(out)}, nil
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result := runDecomposer(context.Background(), store, overflowRunner, rcfg, t.TempDir(), b.ID)
	assert.True(t, result.Failed, "must be marked as failed for >5 children")
	assert.Equal(t, "invalid_count", result.Reason)
}

